solution_code:
#include <iostream>
#include <string>

struct Color
{
    std::string label;
    int r;
    int g;
    int b;
};

int main()
{
    int r{}, g{}, b{};
    std::string label;

    std::cin >> r >> g >> b >> label;

    Color custom { label, r, g, b };
    Color red { .label = "Red", .r = 255 };
    Color green { .label = "Green", .g = 255 };
    Color black {};
    black.label = "Black";

    std::cout << custom.label << ": " << custom.r << ' ' << custom.g << ' ' << custom.b << '\n';
    std::cout << red.label << ": " << red.r << ' ' << red.g << ' ' << red.b << '\n';
    std::cout << green.label << ": " << green.r << ' ' << green.g << ' ' << green.b << '\n';
    std::cout << black.label << ": " << black.r << ' ' << black.g << ' ' << black.b << '\n';

    return 0;
}
